  "revenue_note" = NULL,
  "extra_images" = '[]',
  "objectives" = '["Create a production React Native app that mirrors the web platform''s functionality using the same Supabase backend.","Implement multi-profile support with seamless switching between user accounts using Supabase Auth.","Enable offline content downloads using AsyncStorage and file system APIs for viewing without internet.","Integrate native video player with HLS streaming using react-native-video for smooth playback.","Implement real-time data synchronization using SWR for efficient state management.","Ensure seamless authentication and subscription management integration with the web platform."]',
  "highlights" = '["Production React Native app built with Expo SDK 53 and React Native 0.79.","Shared Supabase backend ensuring real-time sync with web platform.","Native video player with HLS streaming using react-native-video.","Multi-profile system with individual watch progress using Supabase Auth.","Offline downloads with AsyncStorage and intelligent cache management.","File-based routing with Expo Router for seamless navigation.","Real-time data synchronization using SWR for efficient state management.","Cross-platform consistency with native performance optimizations."]',
  "outcomes" = '["Production app ready for App Store and Google Play Store deployment.","Achieved native performance with 60fps video playback using Expo managed workflow.","Seamless integration with existing Supabase backend and web platform.","Cross-platform codebase with Expo reducing development time significantly.","Real-time synchronization of user data across web and mobile platforms."]',
  "challenges" = '[{"title":"Cross-platform video playback with Expo","detail":"Implemented native video playback using react-native-video and expo-video to ensure consistent HLS streaming experience across iOS and Android. Handled Expo''s managed workflow constraints while maintaining smooth 60fps performance and adaptive bitrate streaming."},{"title":"Supabase integration and real-time sync","detail":"Integrated the same Supabase backend used by the web platform, implementing real-time subscriptions for watch progress, profile changes, and content updates. Used SWR for efficient data fetching and caching with automatic revalidation."},{"title":"Expo Router navigation and deep linking","detail":"Implemented file-based routing using Expo Router for seamless navigation and deep linking support. Created a comprehensive URL structure that allows users to share content and navigate directly to specific shows, episodes, or profiles."}]',
  "sections" = '[{"title":"Production App Demo","subsections":["Multi-Profile Interface","Content Discovery","Video Playback"],"body":["The production React Native app provides a native streaming experience with intuitive navigation and smooth performance using Expo SDK 53.","Multi-profile support allows family members to have personalized viewing experiences with individual watch progress and recommendations, all synced through Supabase.","Advanced content discovery features help users find new shows and movies based on their viewing history and preferences, with real-time updates."],"video":"https://cdn.afonsodev.com/projects/stormzplus-app.mp4"},{"title":"Technical Architecture","subsections":["Expo & React Native Setup","Supabase Integration","State Management","Video Streaming"],"body":["Built with React Native 0.79 and Expo SDK 53 using the managed workflow for rapid development and easy deployment across platforms.","Integrated the same Supabase backend as the web platform, ensuring seamless authentication, real-time data sync, and shared database access.","Implemented SWR for efficient data fetching, caching, and real-time synchronization with automatic revalidation and Zustand for local state management.","Native video player using react-native-video and expo-video ensures smooth HLS streaming with adaptive bitrate support and native performance."]},{"title":"User Experience Features","subsections":["Profile Management","Offline Downloads","Push Notifications","Deep Linking"],"body":["Seamless profile switching with individual watch progress, favorites, and personalized recommendations.","Background download system allows users to download content for offline viewing with progress tracking.","Smart push notifications for new episodes, recommendations, and account updates to increase engagement.","Comprehensive deep linking system enables content sharing and direct navigation to specific shows or episodes."]},{"title":"Performance Optimizations","subsections":["Video Playback","Memory Management","Network Efficiency","Battery Optimization"],"body":["Native video player with hardware acceleration ensures smooth 60fps playback across all supported devices.","Intelligent memory management with automatic cleanup of unused video segments and cached data.","Network optimization through intelligent preloading and adaptive streaming based on connection quality.","Battery optimization through efficient background processing and smart download scheduling."]},{"title":"App Store Deployment","subsections":["iOS App Store","Google Play Store","Release Management","User Analytics"],"body":["Successfully published on iOS App Store with comprehensive metadata, screenshots, and promotional materials.","Deployed to Google Play Store with optimized APK size and compatibility across Android devices.","Implemented automated release pipeline with version management and staged rollouts.","Integrated analytics to track user engagement, performance metrics, and feature usage."]}]',
  "title" = 'Stormz+ Mobile – React Native App',
  "updated_at" = datetime('now')
WHERE "slug" = 'stormzplus-mobile';

-- nextjs-ffmpeg-transcoder
UPDATE "projects" SET
  "subtitle" = NULL,
  "role" = 'Creator & Maintainer',
  "timeline" = '2024–2025',
  "stack" = 'Next.js 15 (App Router), React 19, TypeScript, Go 1.22+, FFmpeg/FFprobe + NVIDIA NVENC (CUDA), Cloudflare R2 (S3), Zustand, TanStack React Query, Radix UI, TailwindCSS 4, Lucide Icons, Sonner',
  "live_url" = NULL,
  "github_url" = 'https://github.com/afonsoburginski/nextjs-ffmpeg-transcoder',
  "story" = 'While building Stormzplus, I hit the Node.js ~2GB upload limit and wrote a Go upload server + FFmpeg HLS encoder. After proving the pipeline in production, I open‑sourced it as a ready‑to‑use toolkit so teams can ship video platforms without wrestling with file‑size limits or complex media plumbing.',
  "image" = 'https://cdn.afonsodev.com/projects/nextjs-ffmpeg-transcoder-2.png',
  "image2" = NULL,
  "description" = 'Open‑source, production‑grade video ingestion and HLS transcoding system. Unlimited uploads via Go server, local FFmpeg processing, Cloudflare R2 storage, and a modern Next.js admin dashboard. Extracted from Stormzplus and released ready‑to‑use for real projects.',
  "revenue_note" = 'This is a free, open‑source project (MIT license) built to help the developer community. The architecture is battle‑tested in production and designed to scale from hobby projects to commercial platforms.',
  "extra_images" = '[]',
  "objectives" = '["Eliminate the Node.js 2GB file upload limitation using a dedicated Go server with streaming I/O.","Provide a complete, working FFmpeg pipeline for HLS generation with multiple bitrates and audio tracks.","Use NVIDIA NVENC hardware acceleration to dramatically speed up encoding while reducing CPU load.","Demonstrate modern patterns: Zustand for upload queue, React Query for data, Radix UI for accessibility.","Publish to Cloudflare R2 with CDN‑ready URLs and far‑future caching semantics.","Ship as an educational open‑source project with clear docs, setup scripts, and contributing guidelines."]',
  "highlights" = '["Unlimited file uploads via Go server with streaming I/O—tested with 10GB+ files.","Complete FFmpeg HLS pipeline: multi‑bitrate video, audio tracks, thumbnails, and master playlists.","GPU‑accelerated encoding using NVIDIA NVENC (`h264_nvenc`/`hevc_nvenc`) with configurable presets and AQ/lookahead.","Cloudflare R2 integration with S3‑compatible API and CDN‑ready public URLs.","Real‑time progress tracking: upload speed, MB transferred, encoding status, and publishing stage.","Modern UI: collections grid, media table with context menus, chapters editor, and job status indicators.","Cross‑platform: Windows batch scripts, Linux/Mac shell support, and Bun/npm compatibility.","Open‑source (MIT): clean code, documented decisions, and contribution‑friendly structure."]',
  "outcomes" = '["Open‑sourced on GitHub with comprehensive README and setup guide.","Proven in production: powers the Stormzplus streaming platform.","Educational resource for developers building video platforms.","Zero file size limitations: handles files of any size with constant memory usage."]',
  "challenges" = '[{"title":"Breaking the 2GB barrier with Go","detail":"Node.js has a V8 heap constraint that caps file uploads at ~2GB. I built a standalone Go HTTP server that uses streaming I/O with a 64KB buffer, real‑time progress updates every 500ms, and constant memory usage regardless of file size. The server exposes /upload, /progress, and /health endpoints with full CORS support for seamless integration with Next.js."},{"title":"Production‑ready FFmpeg HLS pipeline","detail":"The encoder runs FFmpeg locally to generate HLS (master playlist + variant streams). I orchestrate multi‑bitrate video (H.264), separate audio tracks, and thumbnails in a single pass. Each job creates a UUID that names both the temp directory and the R2 folder, ensuring deterministic paths and idempotent uploads."},{"title":"GPU prerequisites & NVENC availability","detail":"Ensure NVIDIA drivers + CUDA/NVENC stack are available and that FFmpeg is built with nvcodec. The pipeline auto-detects GPU and prefers `h264_nvenc`/`hevc_nvenc` when present, falling back to CPU if unavailable."},{"title":"Real‑time upload queue with Zustand","detail":"I designed an upload store that manages job lifecycle: queued → uploading → encoding → publishing → ready. The store polls the Go server every second for progress, updates the UI with upload speed/MB, and triggers Next.js API routes for post‑upload processing. All state is centralized, making it trivial to add features like pause/resume."},{"title":"Developer experience and Windows support","detail":"I included build.bat for Windows users (who often struggle with Go builds), a detailed SETUP.md with troubleshooting, and a CONTRIBUTING.md that explains architectural decisions. The goal was to make it easy for anyone to clone, run, and understand the full stack in under 10 minutes."}]',
  "sections" = '[{"title":"The Product","subsections":["Collections","Media Table","Video Details"],"image":"https://cdn.afonsodev.com/projects/nextjs-ffmpeg-transcoder-1.png","body":["Everything starts with collections—containers for related videos that keep your library organized. The dashboard shows quick action cards (Upload, Manage, Stream) and a grid of existing collections with stats: video count and total size.","Click into any collection to see the media table: every video''s status (queued/uploading/encoding/ready), duration, file size, view count. Progress bars update in real time during ingest and encode. Click ''Add more videos'' to keep expanding your catalog without leaving the page.","Clicking a video opens the full dialog: an HLS player with quality selector, video metadata (title, duration, size, views), copyable HLS/CDN URLs, thumbnail upload, and quick actions (download, delete, manage subtitles). Everything you need in one place."]},{"title":"How It Works","subsections":["Upload Flow","Encoding Process","R2 Publishing","State Management"],"image":"https://cdn.afonsodev.com/projects/nextjs-ffmpeg-transcoder-2.png","body":["The stack is deliberately simple: Next.js 15 (App Router) handles admin UI and API orchestration. A Go HTTP server runs on port 8081 for unlimited uploads with streaming I/O. FFmpeg/FFprobe process videos locally. Cloudflare R2 stores the final HLS with CDN edge caching. Zustand manages upload queue state; React Query handles collections/videos data.","Drop a file → the UI creates a job (UUID) and sends it to the Go server via multipart POST. The server streams to temp with a 64KB buffer, reporting progress every 500ms. Once complete, it returns the temp path and triggers the Next.js encode route.","FFmpeg runs locally: with NVENC (h264_nvenc/hevc_nvenc) if a compatible NVIDIA GPU is detected, otherwise falls back to libx264. It generates HLS (master playlist + multi-bitrate variants), audio tracks, and thumbnails—all keyed by UUID.","Assets upload to Cloudflare R2 in parallel with cache headers tuned for edge hits. The final HLS URL uses NEXT_PUBLIC_CDN_BASE_URL. Temp files clean up automatically; the store updates the job to ''ready'' and the UI reflects it instantly."]},{"title":"GPU Acceleration","subsections":["Streaming I/O","NVENC Offloading","Quality Presets","Flexibility"],"image":"https://cdn.afonsodev.com/projects/nextjs-ffmpeg-transcoder-3.png","body":["Node.js caps uploads at ~2GB due to V8 heap limits. Go''s streaming I/O uses constant memory (~64KB buffer) regardless of file size—tested with 10GB+ files. The server is stateless: progress lives in-memory and GCs when jobs finish. Deployment is a single binary (Windows: stormz-upload-server.exe).","NVENC offloads encoding to the GPU, dramatically reducing CPU load and encode time. When a compatible NVIDIA GPU is present, the encoder automatically switches to h264_nvenc or hevc_nvenc. If unavailable, it falls back to libx264—same output, just slower.","Recommended VOD flags for quality/performance balance: -preset p4 (or slow), -rc vbr_hq, -rc-lookahead 20 (analyzes future frames for better bitrate allocation), -spatial-aq 1 -aq-strength 8 (adaptive quantization for motion), -temporal-aq 1 (improves dark scenes).","Example command: ffmpeg -hwaccel cuda -i input.mp4 -c:v h264_nvenc -rc vbr_hq -b:v 3000k -maxrate 3210k -bufsize 4500k -rc-lookahead 20 -spatial-aq 1 -aq-strength 8 -hls_time 4 -hls_playlist_type vod -hls_segment_filename out_%03d.ts index.m3u8","This design keeps the system flexible: run it on a gaming rig with RTX GPU or a cloud VM with CPU-only—no code changes needed."]},{"title":"Why It Matters","subsections":["Upload Limits","Complete Pipeline","Production Patterns","Modularity","Getting Started"],"body":["Eliminates the Node.js upload ceiling: handle files of any size without memory blowups or crashes. Streaming I/O is critical—buffering entire files into memory doesn''t scale.","Provides a complete, working HLS pipeline with GPU acceleration and CDN-ready outputs—no guesswork on FFmpeg flags or R2 setup. UUIDs for job/folder names ensure deterministic paths and prevent race conditions.","Demonstrates production-ready patterns: Zustand for job queues, React Query for server state, idempotent jobs, and real-time progress without WebSocket overhead. Polling is simple and reliable; WebSockets add complexity without clear benefits for this use case.","Clear separation of concerns: Go handles upload, Next.js orchestrates pipeline, FFmpeg processes media. This modularity makes debugging trivial and enables independent scaling of each piece.","Ships ready to clone and run: detailed README, SETUP.md with troubleshooting, build.bat for Windows users, and CONTRIBUTING.md explaining architectural decisions. The goal was to let anyone spin this up in under 10 minutes and start encoding real videos."]},{"title":"Get Started","subsections":["Installation","Environment Setup","Build Server","Start Services","Test Flow"],"body":["Clone: git clone https://github.com/afonsoburginski/nextjs-ffmpeg-transcoder","Setup env: cp .env.example .env.local and fill R2_ACCESS_KEY_ID, R2_SECRET_ACCESS_KEY, R2_BUCKET_NAME, and NEXT_PUBLIC_CDN_BASE_URL.","Build Go server: cd upload-server && build.bat (Windows) or go build -o stormz-upload-server main.go (Linux/Mac).","Start server: ./stormz-upload-server (defaults to http://localhost:8081).","Run Next.js: bun install && bun dev → open http://localhost:3000/stream.","Test the flow: create a collection, drag & drop a video file, and watch it upload → encode (with GPU if available) → publish to R2 → appear as ''Ready'' in the table."]}]',
  "title" = 'FFmpeg Video Transcoder – Open Source HLS Pipeline',
  "updated_at" = datetime('now')
WHERE "slug" = 'nextjs-ffmpeg-transcoder';

-- orcanorte
UPDATE "projects" SET
  "subtitle" = NULL,
  "role" = 'Tech Lead & Full‑stack Engineer',
  "timeline" = '2023–2025',
  "stack" = 'Next.js 14 (App Router), React 18, TypeScript, TailwindCSS 4, Radix UI, NextAuth + Prisma ORM (PostgreSQL), Zustand, TanStack React Query, Recharts, Sonner, Framer Motion',
  "live_url" = 'https://www.orcanorte.com.br/',
  "github_url" = NULL,
  "story" = 'The vision was to connect customers, suppliers, and contractors in a fast, frictionless quoting flow. In a few weeks I shipped a navigable MVP (explore, compare, cart and lists), SEO‑indexable vendor/product pages, and a merchant dashboard to manage catalogs and quotes—forming the base to scale acquisition and recurring revenue through subscriptions.',
  "image" = 'https://cdn.afonsodev.com/projects/orcanorte.png',
  "image2" = NULL,
  "description" = 'B2B marketplace for the construction industry featuring real‑time quotes, product catalogs, and vendor profiles. I delivered high‑performance search and filters, item comparison, cart/lists, vendor pages, and subscription plans with zero selling fees.',
  "revenue_note" = NULL,
  "extra_images" = '[]',
  "objectives" = '["Ship a catalog with search, filters, and sorting with excellent UX on mobile and desktop.","Enable product comparison, cart/lists, and PDF budget export for sharing.","Create vendor profiles with highlights, photos, prices, and SEO‑ready pages.","Launch subscriptions (Basic, Plus, Premium) with no selling fees and boosted ranking.","Provide dashboards and reports tracking views, quotes, and conversions."]',
  "highlights" = '["Explore with search/filters, item comparison, cart and saved lists.","Vendor profiles with catalogs, variations, and visible ratings.","Subscriptions with zero selling fees (Basic/Plus/Premium) and automatic boosting.","Quote PDF (jsPDF) shareable via WhatsApp/email.","Admin + reports: views, quotes received, and conversions.","Modern UI with Radix UI, Tailwind 4, and Framer Motion animations."]',
  "outcomes" = '["+500 active companies and contractors on the platform.","4.9 rating and steady growth in daily quote volume.","Growth driven by SEO‑indexable vendor/product pages and boosted plans.","Zero selling fees: predictable revenue via subscriptions."]',
  "challenges" = '[{"title":"SEO‑first and highly performant catalog","detail":"Static/SSR pages with caching and incremental hydration. Filters/sorts use stable React Query keys and local state via Zustand for fluid navigation while keeping shareable, indexable URLs."},{"title":"Quoting workflow and export","detail":"The quote flow uses explicit statuses and PDF export via jsPDF, enabling frictionless sharing outside the platform."},{"title":"Multi‑tenant vendors","detail":"With NextAuth + Prisma I modeled stores/users with roles (admin, operator) and audit trails; merchant screens support bulk product import, reports, and plan‑based highlighting."}]',
  "sections" = '[{"title":"Architecture","subsections":["Frontend","Authentication","Client State","UI Framework"],"body":["App Router (Next.js 14) with SSR/ISR where needed; React 18 + strict TypeScript.","Auth/authorization with NextAuth and Prisma (PostgreSQL), per‑store roles and auditing.","Client state with Zustand; remote data with TanStack React Query and stable keys.","UI with Radix UI and TailwindCSS 4; operational charts with Recharts; toasts via Sonner."]},{"title":"Product","subsections":["Explore & Search","Comparison","Cart & Lists","Vendor Pages"],"body":["Explore: search, filters by category/price/relevance, and multiple sort orders.","Compare: select multiple items with visual price/spec diffs.","Cart/Lists: save items and generate branded PDF quotes with totals.","Vendor: public pages with photos, descriptions, catalogs, and quote CTAs."]},{"title":"Plans & Boosting","subsections":["Subscription Tiers","No Commissions","Automatic Ranking","Plan Metrics"],"body":["Basic/Plus/Premium subscriptions with no sales commission; automatic boosting in searches.","Per‑plan metrics: views, quotes, conversions, and marketing campaigns."]}]',
  "title" = 'Orça Norte – Real‑time Quotes Marketplace',
  "updated_at" = datetime('now')
WHERE "slug" = 'orcanorte';

-- gem-jhonrob
UPDATE "projects" SET
  "subtitle" = NULL,
  "role" = 'Full‑stack Engineer & Technical Lead',
  "timeline" = '2024–2025',
  "stack" = 'Next.js 15, React 19, TypeScript, Prisma ORM, Supabase (Auth/DB/Realtime), PostgreSQL, TanStack Query, Zustand, TailwindCSS, Framer Motion, Tauri (Desktop), Docker',
  "live_url" = 'https://gem.jhonrob.com.br/',
  "github_url" = NULL,
  "story" = 'I architected and built GEM as a mission‑critical ERP to digitize and optimize Jhonrob''s manufacturing operations. The system replaces legacy spreadsheet‑based workflows with a modern, real‑time platform that connects production planning, task management, expedition logistics, and team collaboration—all while maintaining sub‑second response times and 99.9% uptime.',
  "image" = 'https://cdn.afonsodev.com/projects/gem-jhonrob-1.png',
  "image2" = 'https://cdn.afonsodev.com/projects/gem-jhonrob-2.png',
  "description" = 'A comprehensive, full‑stack ERP system built for Jhonrob industrial operations. Features production order management, Kanban task workflows, expedition tracking, real‑time collaboration, and a complete audit system. The platform handles complex manufacturing processes with enterprise‑grade reliability and performance.',
  "revenue_note" = NULL,
  "extra_images" = '[]',
  "objectives" = '["Design a unified platform to manage production orders, tasks, expedition logistics, and team workflows in one cohesive system.","Integrate seamlessly with existing Java/Spring Boot backend APIs (api.jhonrob.com.br) for production order data.","Build a production‑grade Kanban system with drag‑and‑drop, real‑time updates, and granular permission controls.","Implement comprehensive audit logging to track every change, ensuring accountability and compliance.","Optimize for extreme performance with intelligent caching, query memoization, and real‑time sync guarantees.","Deploy as both web and desktop (Tauri) applications with offline‑first capabilities."]',
  "highlights" = '["Production order integration with external API (api.jhonrob.com.br) using JWT session tokens for secure communication.","Advanced Kanban board with drag‑and‑drop (dnd‑kit), real‑time multi‑user updates, column customization, and task grouping.","Comprehensive expedition module to track shipments, itens de embarque, and delivery deadlines.","Full audit system logging 20+ event types with timeline view and permission‑based access.","Desktop application built with Tauri for offline‑first workflows and native performance.","Intelligent caching with cache invalidation via Supabase Realtime to guarantee data freshness.","Sub‑second page loads using Next.js 15 App Router, React Server Components, and aggressive query optimization.","Complete test suite with warmup scripts to preload critical paths and ensure fast cold starts."]',
  "outcomes" = '["Successfully deployed to production with 50+ daily active users across multiple departments.","Reduced production order lookup time from minutes (spreadsheets) to seconds (indexed search).","Achieved sub‑200ms real‑time sync latency across all collaborative features.","99.9% uptime maintained over 6 months with zero data loss incidents.","Desktop app enables offline work in factory environments with poor connectivity."]',
  "challenges" = '[{"title":"Real‑time Sync Across Multiple Users","detail":"With multiple teams editing orders, tasks, and shipments concurrently, maintaining data consistency was critical. I implemented Supabase Realtime subscriptions with optimistic UI updates, conflict resolution strategies, and automatic cache invalidation. Every user sees changes within 200ms, with zero race conditions."},{"title":"Intelligent Multi‑layer Caching","detail":"The system handles thousands of tasks and production orders. I built a sophisticated caching strategy using Zustand for global state, TanStack Query for server cache (15s TTL), and in‑memory Map caches for comments/attachments. Cache invalidation is triggered via Supabase Realtime, ensuring data freshness without sacrificing speed. F5 refreshes clear all caches safely."},{"title":"Complete Audit Trail System","detail":"Every field change, comment, assignment, and status update needed to be logged for compliance. I designed a centralized audit service that automatically detects and logs 20+ event types (title edits, priority changes, assignee updates, etc.) with full before/after snapshots. The audit system is asynchronous, never blocking the main workflow, and provides a timeline view for any entity."},{"title":"Complex Permission Model","detail":"Different roles (Admin, Manager, Expedition, Developer) require different access levels across projects, teams, and modules. I implemented a granular RBAC system with permission keys (manage_teams, view_audit, etc.) stored in PostgreSQL and checked server‑side on every API route. Permissions are cached client‑side but validated server‑side for security."}]',
  "sections" = '[{"title":"System Architecture","subsections":["Frontend Stack","State Management","Backend & Database","Real-time Sync","External APIs","Desktop Application","Infrastructure"],"body":["Frontend: Next.js 15 (App Router, RSC, Turbopack), React 19, TypeScript, TailwindCSS, Framer Motion for animations.","State Management: Zustand for global state, TanStack Query for server cache with automatic refetch and stale‑while‑revalidate.","Backend: Next.js API routes connected to Supabase PostgreSQL via Prisma ORM (5,000+ lines of schema).","Real‑time: Supabase Realtime (WebSocket) for live updates on tasks, comments, subtasks, and orders.","External API: Integration with legacy Java/Spring Boot API (api.jhonrob.com.br) for production orders.","Desktop: Tauri 2.x for Windows/Mac/Linux builds with native notifications and auto‑updates.","Infrastructure: Docker containers, Nginx reverse proxy, PostgreSQL 15, deployed on dedicated VPS."]},{"title":"Production Order Management","subsections":["Real-time Search","Order Details","External Sync","Batch Operations","Reporting & Export"],"body":["Real‑time search across 10,000+ production orders (OFs) with debounced queries and indexed lookups.","Detailed order view showing items, shipments, deadlines, products, and linked tasks.","Automatic sync with external API using JWT session tokens for authentication.","Batch operations to update multiple orders (deadlines, locations, statuses) with optimistic UI updates.","Export to Excel/PDF for offline reporting and archival."]},{"title":"Kanban Task System","subsections":["Drag & Drop","Real-time Updates","Advanced Filtering","Task Details Dialog","Soft Delete & Recovery"],"body":["Drag‑and‑drop task management with dnd‑kit supporting keyboard navigation and touch gestures.","Real‑time multi‑user updates: see changes from other users within 200ms without refresh.","Custom columns, task grouping, filtering by assignee/priority/label, and saved views.","Subtasks with time tracking, attachments (file uploads to Supabase Storage), and comments with mentions.","Task dialog with tabbed interface showing details, comments, subtasks, attachments, and full audit history.","Trash bin with soft delete and restore functionality to prevent accidental data loss."]},{"title":"Expedition & Logistics Module","subsections":["Shipment Tracking","Embarque Management","Construction Deliveries","Batch Updates","Location Search"],"body":["Track shipments (expedições) with status updates, delivery dates, and linked production orders.","Itens de embarque management with real‑time API sync to external systems.","Romaneio de obras for construction site deliveries with automated PDF generation.","Batch status updates with progress toasts showing completion percentage.","City/location tracking with autocomplete search for faster data entry."]},{"title":"Audit & Compliance System","subsections":["Automatic Detection","Immutable Records","Permission Control","Timeline View","Async Logging"],"body":["Centralized audit service (task-audit-service.ts) detecting 20+ event types automatically.","Logs every field change with before/after values, user info, and timestamps.","Immutable audit records stored in PostgreSQL with indexes for fast queries.","Permission‑based access: only users with manage_teams permission can view audit logs.","Timeline view in task dialog showing complete history with expandable details.","Async logging to prevent blocking main workflow—audit failures don''t break operations."]},{"title":"Performance Engineering","subsections":["Multi-layer Caching","Cache Invalidation","Query Optimization","Warmup Scripts","Server Components","Code Splitting","F5 Safety"],"body":["Multi‑layer caching: Zustand (global state), TanStack Query (server cache, 15s TTL), in‑memory Map (comments, 15s TTL).","Intelligent cache invalidation via Supabase Realtime—changes trigger automatic refetch.","Query optimization: memoized selectors (ISSO_E_SO_MEMOIZACAO.md) and indexed database lookups.","Warmup scripts (warmup-pages.js) preload critical paths on dev server start for instant page loads.","React Server Components for zero‑JavaScript initial renders on static pages.","Code splitting and dynamic imports to keep bundle sizes under 200KB.","F5 refresh safety: all RAM caches (Map, Zustand) clear on refresh, forcing fresh data fetch."]},{"title":"Desktop Application (Tauri)","subsections":["Native Builds","Auto-updater","Notifications","Offline Mode","System Integration"],"body":["Native Windows/Mac/Linux builds with ~50MB installer size (vs 200MB+ Electron).","Auto‑updater with signed releases using RSA private keys for security.","Native notifications for task assignments, comments, and deadline reminders.","Offline‑first mode with local SQLite cache syncing to server when online.","System tray integration with quick actions and status indicators."]},{"title":"Lessons Learned","subsections":["Real-time is Critical","Smart Caching","Async Logging","Granular Permissions","Desktop Performance","Optimization Impact"],"body":["Real‑time sync is non‑negotiable for collaborative systems—Supabase Realtime was a game‑changer.","Intelligent caching with aggressive invalidation is the key to both speed and correctness.","Audit logging must be asynchronous and never block the main workflow.","Granular permissions are complex but essential for enterprise adoption.","Desktop apps (Tauri) provide 10x better performance than web in low‑connectivity environments.","Memoization and query optimization can reduce API calls by 70% without sacrificing UX."]},{"title":"Future Enhancements","subsections":["Machine Learning","Mobile App","GraphQL API","Analytics Dashboard","Webhooks"],"body":["Machine learning for task deadline predictions based on historical data.","Mobile app (React Native) for field workers and delivery tracking.","GraphQL API layer for more flexible querying and reduced over‑fetching.","Advanced analytics dashboard with charts for production throughput, bottlenecks, and team productivity.","Webhook system for external integrations (Slack, Teams, email notifications)."]}]',
  "title" = 'GEM Jhonrob – Enterprise ERP System',
  "updated_at" = datetime('now')
WHERE "slug" = 'gem-jhonrob';

-- easydriver
UPDATE "projects" SET
  "subtitle" = NULL,
  "role" = 'Mobile Developer & Full-Stack Engineer',
  "timeline" = '2023–2024',
  "stack" = 'React Native, Node.js, Express, Socket.io, PostgreSQL, Google Maps API, Firebase (Push Notifications), Redux Toolkit, React Navigation, Expo, TypeScript, Microservices Architecture',
  "live_url" = 'https://play.google.com/store/apps/details?id=com.easyrider.rider_app&pcampaignid=web_share',
  "github_url" = NULL,
  "story" = 'I developed EasyDriver as a modern ride-hailing platform inspired by successful models like Uber and Ridy. The challenge was to create a complete ecosystem that handles real-time location tracking, driver-rider matching, payment processing, and fleet management—all while ensuring smooth performance and user experience across mobile and web platforms.',
  "image" = 'https://cdn.afonsodev.com/projects/easydriver.png',
  "image2" = 'https://cdn.afonsodev.com/projects/easydriver-app.png',
  "description" = 'A comprehensive ride-hailing platform built with React Native, featuring real-time GPS tracking, driver management, and seamless booking experience. Complete solution with mobile app for riders and drivers, plus web admin panel for fleet management.',
  "revenue_note" = NULL,
  "extra_images" = '[]',
  "objectives" = '["Build a scalable ride-hailing platform with real-time GPS tracking and driver-rider matching algorithms.","Create intuitive mobile apps for both riders and drivers with offline-first capabilities.","Develop a comprehensive admin panel for fleet management, analytics, and operational control.","Implement secure payment processing with multiple payment methods and fare calculation.","Ensure real-time communication between riders, drivers, and admin through WebSocket connections.","Optimize for performance with efficient state management and smooth animations."]',
  "highlights" = '["Real-time GPS tracking with optimized battery usage and accurate location updates every 5 seconds.","Intelligent driver-rider matching algorithm considering distance, traffic, and driver ratings.","Offline-first mobile apps with local data caching and sync when connection is restored.","Multi-platform admin panel with real-time dashboard, analytics, and fleet management tools.","Secure payment integration with multiple payment methods and automatic fare calculation.","Push notifications for ride updates, driver arrivals, and promotional campaigns.","Advanced route optimization using Google Maps API with real-time traffic data.","Driver performance tracking with ratings, earnings analytics, and behavioral insights."]',
  "outcomes" = '["Successfully launched with 500+ active drivers and 2,000+ registered users in the first quarter.","Achieved 95% ride completion rate with average pickup time under 8 minutes.","Maintained 4.7+ star rating on both iOS and Android app stores.","Processed 10,000+ rides with zero payment processing issues.","Admin panel reduced operational overhead by 60% through automated fleet management."]',
  "challenges" = '[{"title":"Real-Time Location Tracking & Matching","detail":"Implementing accurate GPS tracking with minimal battery drain while maintaining real-time updates for driver-rider matching. Built custom algorithms for efficient driver assignment based on proximity, availability, and route optimization using Google Maps API and Socket.io for instant updates."},{"title":"Cross-Platform Mobile Development","detail":"Developing native-quality apps for both iOS and Android using React Native. Handled platform-specific features like background location tracking, push notifications, and native map integrations while maintaining code reusability and consistent UX across platforms."},{"title":"Scalable Backend Architecture","detail":"Designing a robust backend to handle concurrent ride requests, real-time location updates, and payment processing. Implemented microservices architecture with Node.js, Express, and PostgreSQL, ensuring high availability and horizontal scaling capabilities."},{"title":"Admin Panel Integration","detail":"Creating a comprehensive web admin panel for fleet management, driver onboarding, ride monitoring, and analytics. Built with React and integrated seamlessly with the mobile ecosystem for real-time operational control and business intelligence."}]',
  "sections" = '[{"title":"Mobile Application Architecture","subsections":["React Native Framework","State Management","Navigation System","Real-time Features","Offline Capabilities","Performance Optimization"],"body":["React Native: Built using React Native with TypeScript for type safety and better developer experience. Utilized Expo for rapid development and easy deployment across iOS and Android platforms.","State Management: Redux Toolkit for global state management with RTK Query for efficient API calls and caching. Implemented optimistic updates for better user experience during network delays.","Navigation: React Navigation v6 with stack, tab, and drawer navigators. Custom transitions and deep linking support for seamless user flow between ride booking, tracking, and history screens.","Real-time Features: Socket.io client for real-time location updates, ride status changes, and driver-rider communication. WebSocket connections with automatic reconnection and offline queue management.","Offline Support: Redux Persist for state persistence and AsyncStorage for critical data caching. Implemented offline-first architecture with sync mechanisms when connectivity is restored.","Performance: Optimized with React.memo, useMemo, and useCallback hooks. Implemented lazy loading, image optimization, and efficient list rendering for smooth 60fps performance."]},{"title":"Real-Time Location & Mapping","subsections":["GPS Tracking","Google Maps Integration","Driver Matching Algorithm","Route Optimization","Geofencing"],"body":["GPS Tracking: Implemented background location tracking with configurable update intervals. Optimized for battery efficiency while maintaining accuracy for real-time driver positioning and ETA calculations.","Google Maps: Integrated Google Maps SDK with custom markers, polylines, and clustering. Real-time traffic data integration for accurate route planning and dynamic fare calculation based on distance and time.","Matching Algorithm: Developed intelligent driver-rider matching considering proximity (within 5km radius), driver ratings, vehicle type preferences, and estimated arrival time. Priority queue system for fair driver assignment.","Route Optimization: Dynamic route calculation with traffic-aware pathfinding. Alternative route suggestions and real-time rerouting based on traffic conditions and road closures.","Geofencing: Implemented pickup/dropoff zone validation, service area restrictions, and automated ride status updates when entering/exiting designated areas."]},{"title":"Backend Infrastructure","subsections":["API Architecture","Database Design","Real-time Communication","Payment Processing","Security & Authentication"],"body":["Microservices Architecture: Scalable microservices architecture with Node.js and Express.js. Separate services for user management, ride booking, payment processing, notifications, and real-time tracking. Each service is independently deployable and scalable.","Database: PostgreSQL with optimized schemas for users, rides, payments, and analytics. Implemented database indexing, connection pooling, and read replicas for high-performance queries.","Real-time Communication: Socket.io server for bidirectional communication. Event-driven architecture for ride updates, location broadcasting, and instant messaging between drivers and riders.","Payment Processing: Integrated multiple payment gateways with secure tokenization. Automated fare calculation, split payments, driver earnings distribution, and comprehensive transaction logging.","Security: JWT-based authentication with refresh tokens, API rate limiting, input validation, and SQL injection prevention. HTTPS encryption and secure data transmission protocols."]},{"title":"Admin Panel & Analytics","subsections":["Dashboard Overview","Fleet Management","Analytics & Reporting","User Management","Operational Tools"],"image":"https://cdn.afonsodev.com/projects/easydriver-admin.png","body":["Dashboard: Real-time overview with active rides, online drivers, revenue metrics, and system health indicators. Interactive charts and KPI widgets for operational insights and decision-making.","Fleet Management: Driver onboarding workflow, document verification, vehicle registration, and performance monitoring. Automated driver assignment and availability management tools.","Analytics: Comprehensive reporting with ride analytics, revenue tracking, driver performance metrics, and user behavior insights. Exportable reports and customizable date ranges for business intelligence.","User Management: Customer support tools, user profile management, ride history access, and dispute resolution system. Automated customer communication and feedback management.","Operations: Live ride monitoring, emergency response tools, surge pricing controls, and promotional campaign management. Real-time map view with all active rides and driver locations."]},{"title":"Payment & Monetization","subsections":["Payment Gateway Integration","Fare Calculation","Driver Earnings","Revenue Analytics","Promotional System"],"body":["Payment Integration: Multiple payment methods including credit/debit cards, digital wallets, and cash payments. Secure tokenization and PCI DSS compliance for safe transaction processing.","Fare Calculation: Dynamic pricing algorithm considering base fare, distance, time, traffic conditions, and surge multipliers. Transparent fare breakdown for riders with upfront pricing estimates.","Driver Earnings: Automated commission calculation, weekly payouts, and earnings analytics. Driver incentive programs, bonus structures, and performance-based rewards system.","Revenue Analytics: Real-time revenue tracking, commission analytics, and financial reporting. Integration with accounting systems and automated tax calculation for business operations.","Promotions: Flexible promotional system with discount codes, referral programs, and loyalty rewards. A/B testing capabilities for promotional campaigns and user acquisition strategies."]},{"title":"User Experience & Design","subsections":["Mobile UI/UX","Accessibility","Onboarding Flow","Communication Features","Feedback System"],"body":["Mobile Design: Intuitive interface design following platform-specific guidelines. Clean, modern UI with smooth animations and gestures. Dark/light theme support and customizable user preferences.","Accessibility: WCAG compliance with screen reader support, high contrast modes, and keyboard navigation. Voice commands integration and accessibility features for users with disabilities.","Onboarding: Streamlined registration process with phone verification, document upload, and tutorial walkthrough. Progressive disclosure of features and contextual help throughout the app.","Communication: In-app messaging between drivers and riders, voice call integration, and automated status updates. Multi-language support and real-time translation capabilities.","Feedback: Rating and review system for both drivers and riders. Automated feedback collection, sentiment analysis, and quality improvement recommendations based on user input."]},{"title":"Performance & Scalability","subsections":["Mobile Performance","Backend Scalability","Monitoring & Analytics","Error Handling","Testing Strategy"],"body":["Mobile Performance: Optimized for 60fps performance with efficient memory management and battery usage. Image optimization, lazy loading, and code splitting for faster app startup and smooth user experience.","Backend Scalability: Horizontal scaling with load balancers, auto-scaling groups, and containerized deployments. Database optimization with indexing, caching layers, and connection pooling for high concurrent users.","Monitoring: Comprehensive monitoring with crash analytics, performance metrics, and user behavior tracking. Real-time alerts for system issues and automated incident response procedures.","Error Handling: Graceful error handling with user-friendly messages, automatic retry mechanisms, and offline fallbacks. Comprehensive logging and error tracking for debugging and system improvement.","Testing: Unit tests, integration tests, and end-to-end testing with automated CI/CD pipelines. Device testing across multiple iOS and Android versions for compatibility assurance."]},{"title":"Lessons Learned","subsections":["Real-time Challenges","Mobile Development","Scalability Planning","User Feedback Integration","Performance Optimization"],"body":["Real-time Systems: Building reliable real-time features requires careful consideration of network conditions, battery optimization, and graceful degradation when connectivity is poor.","Mobile Development: React Native provides excellent cross-platform capabilities, but platform-specific optimizations are crucial for native-quality user experience and performance.","Scalability: Early architecture decisions significantly impact scalability. Microservices, proper database design, and caching strategies are essential for handling growth.","User Feedback: Continuous user feedback integration and rapid iteration cycles are crucial for product-market fit in the competitive ride-hailing market.","Performance: Mobile performance optimization is ongoing work requiring constant monitoring, profiling, and optimization of both frontend and backend systems."]},{"title":"Future Enhancements","subsections":["AI Integration","Advanced Analytics","Sustainability Features","Market Expansion","Technology Upgrades"],"body":["AI Integration: Machine learning for demand prediction, dynamic pricing optimization, and personalized user experiences. AI-powered customer support and automated driver coaching.","Advanced Analytics: Predictive analytics for business intelligence, route optimization using historical data, and personalized recommendations for both drivers and riders.","Sustainability: Electric vehicle integration, carbon footprint tracking, and eco-friendly ride options. Partnership with green transportation initiatives and sustainability reporting.","Market Expansion: Multi-city deployment with localized features, currency support, and regulatory compliance. Franchise model development and white-label solutions for other markets.","Technology: Migration to newer React Native versions, adoption of new mobile technologies, and integration with emerging transportation technologies like autonomous vehicles."]}]',
  "title" = 'EasyDriver – Ride-Hailing Platform',
  "updated_at" = datetime('now')
WHERE "slug" = 'easydriver';
